    parts.push({ text: '</input_assets>' });

    const fullPrompt = `
    <instruction>
        <role>Expert Commercial Compositor and Retoucher</role>
        <task>Composite the input products into a photorealistic lifestyle scene. The product must be the absolute KEY ELEMENT with priority focus.</task>
        <scene_description>${prompt}</scene_description>
        <strict_rules>
            <rule>IDENTITY PRESERVATION: The input images <input_assets> are the ground truth. Do not redraw, re-render, or modify the product design, logo, text, or shape.</rule>
            <rule>COMPOSITING: Treat the product input as a "cutout". Place it into the generated environment. Apply lighting and shadow to blend it, but do not alter the pixels of the product branding.</rule>
            <rule>PRIORITY FOCUS: The product must be the "Hero". It should be prominent, well-lit, and occupy a significant portion of the frame. Do not place it far away or make it small.</rule>
            <rule>PERSPECTIVE: If re-angling the product would distort the text or logo, keep the original angle. Legibility and brand accuracy are more important than perspective.</rule>
            <rule>No extra text or labels in the scene.</rule>
        </strict_rules>
    </instruction>
    `;

    parts.push({ text: fullPrompt });

    return withRetries(async () => {
        const response = await ai.models.generateContent({
            model,
            contents: { parts },
            config: { 
                responseModalities: [Modality.IMAGE, Modality.TEXT],
                imageConfig: { aspectRatio: aspectRatio, imageSize },
                temperature: 0.6,
                thinkingConfig: { thinkingBudget: 8192 }
            }
        });

        const imagePart = response.candidates?.[0]?.content?.parts?.find(p => p.inlineData);
        if (imagePart && imagePart.inlineData) {
            return {
                data: imagePart.inlineData.data,
                mimeType: imagePart.inlineData.mimeType,
            };
        }
        throw new Error("No image was generated in the lifestyle creation step.");

    }, "lifestyle image generation");
};

export const styleVariations = [
    "TEMPLATE_ADAPTATION: Strictly follow the layout structure and design elements of the provided Style Guide/Template (ASSET_2). Replace the content with the provided Product/Lifestyle assets + new copy + Logo (ASSET_3, if available). Retain the vibe."
];

export const generateSingleAd = (
  productAssets: ImageData[],
  lifestyleAsset: ImageData | null,
  styleImage: ImageData,
  logoImage: ImageData | null,
  adCopy: AdCopy,
  specialRequest: string,
  creativeDirection: string,
  aspectRatio: string,
  imageSize: string = '1K',
  includeGooglePlay: boolean = false,
  includeAppStore: boolean = false
): Promise<string> => {
  const model = 'gemini-3-pro-image-preview';

  const badges = [];
  if (includeGooglePlay) badges.push("Google Play Badge");
  if (includeAppStore) badges.push("App Store Badge");

  const prompt = `
<system>
  <role>Expert Digital Compositor</role>
  <objective>Create a professional advertisement by compositing the provided assets. Do not generate new objects for the product.</objective>
</system>

<input_assets>
  <asset id="ASSET_1_PRODUCTS" presence="${productAssets.length > 0 ? 'required' : 'none'}">
     <description>Hero product images. GROUND TRUTH. Treat as a rigid layer. Do not redraw, morph, or filter the product itself. Maintain exact packaging details.</description>
  </asset>

  <asset id="ASSET_2_STYLE_GUIDE" presence="required">
     <description>Reference for LAYOUT, COLOR PALETTE, and TYPOGRAPHY STYLE only. Do not use its content.</description>
  </asset>

  <asset id="ASSET_3_LOGO" presence="${logoImage ? 'required' : 'none'}">
     <description>Brand Logo. Must be included exactly as is (immutable). Place in a standard corner.</description>
  </asset>

  <asset id="ASSET_4_LIFESTYLE" presence="${lifestyleAsset ? 'required' : 'none'}">
     <description>Main visual background. CORE CONTENT IS IMMUTABLE. You are permitted to extend the background (outpaint) ONLY to fit the aspect ratio or create negative space for text. Do not alter existing subjects.</description>
  </asset>
</input_assets>

<special_user_request>
  ${specialRequest || "None"}
</special_user_request>

<text_content_requirements>
  <instruction>
    The following text must be placed on the ad. 
    CRITICAL: The meaning of this text must NOT influence the visual generation of the scene or product. 
    Treat the text as "lorem ipsum" for design purposes - only render the characters, do not illustrate the words.
  </instruction>
  <headline>${adCopy.headline}</headline>
  <description>${adCopy.description}</description>
  <cta>${adCopy.cta}</cta>
  <store_badges>
    ${badges.length > 0 ? `Include: ${badges.join(' and ')}. Place in bottom corners, legible.` : 'None.'}
  </store_badges>
</text_content_requirements>

<creative_direction>
  ${creativeDirection}
</creative_direction>

<strict_constraints>
  <rule priority="CRITICAL">SPECIAL REQUEST PRIORITY: If <special_user_request> is provided and not "None", strictly follow it. It overrides conflicting standard style guidelines or default composition rules.</rule>
  <rule priority="HIGHEST">PRODUCT FIDELITY: The product image (ASSET_1) is sacred. Do not warp, distort, or re-render it. If perspective requires a change that distorts the logo/text, prefer the original angle.</rule>
  <rule priority="HIGHEST">TEXT PLACEMENT SAFETY: Text (Headline, Description, CTA) must be placed in negative space. DO NOT OVERLAY TEXT ON TOP OF THE PRODUCT OR ON TOP OF PEOPLE/FACES.</rule>
  <rule priority="HIGH">LIFESTYLE INTEGRITY: If ASSET_4 is used, preserve its core subjects and lighting. You are PERMITTED to extend/outpaint the background edges to accommodate the target aspect ratio or create negative space for text. Do not remove existing people or objects.</rule>
  <rule>NO HALLUCINATIONS: Do not generate new text, labels, or features on the product. Use the input pixels.</rule>
  <rule>TEXT INDEPENDENCE: Do not use the Ad Copy words to generate visual elements. For example, if the copy says "Splash", do not generate a splash unless the Style Guide or Lifestyle asset already has it. Only use provided visual assets.</rule>
  <rule>LOGO INTEGRITY: Do not distort, recolor, or modify the logo (ASSET_3). Place it clearly.</rule>
  <rule>NO ARTIFACTS: Do not write "ASSET 1", "ASSET 2" or "Headline Here" on the image.</rule>
</strict_constraints>
`;

  const parts: any[] = [];

  // Attach images to prompt in order
  if (productAssets.length > 0) {
      parts.push({ text: '<asset_data id="ASSET_1_PRODUCTS">' });
      productAssets.forEach(asset => {
          parts.push({ inlineData: { data: asset.data, mimeType: asset.mimeType } });
      });
      parts.push({ text: '</asset_data>' });
  }

  parts.push({ text: '<asset_data id="ASSET_2_STYLE_GUIDE">' });
  parts.push({ inlineData: { data: styleImage.data, mimeType: styleImage.mimeType } });
  parts.push({ text: '</asset_data>' });

  if (logoImage) {
      parts.push({ text: '<asset_data id="ASSET_3_LOGO">' });
      parts.push({ inlineData: { data: logoImage.data, mimeType: logoImage.mimeType } });
      parts.push({ text: '</asset_data>' });
  }

  if (lifestyleAsset) {
      parts.push({ text: '<asset_data id="ASSET_4_LIFESTYLE">' });
      parts.push({ inlineData: { data: lifestyleAsset.data, mimeType: lifestyleAsset.mimeType } });
      parts.push({ text: '</asset_data>' });
  }

  parts.push({ text: prompt });

  return withRetries(async () => {
    const response = await ai.models.generateContent({
        model,
        contents: { parts },
        config: { 
            responseModalities: [Modality.IMAGE, Modality.TEXT],
            imageConfig: { aspectRatio, imageSize },
            temperature: 0.6,
            thinkingConfig: { thinkingBudget: 8192 }
        }
    });

    const imagePart = response.candidates?.[0]?.content?.parts?.find(p => p.inlineData);
    if (imagePart && imagePart.inlineData) {
        return `data:${imagePart.inlineData.mimeType};base64,${imagePart.inlineData.data}`;
    }
    throw new Error("No image generated.");
  }, `ad generation`);
};

export const generateAds = async (
  productAssets: ImageData[],
  lifestyleAsset: ImageData | null,
  styleImage: ImageData,
  logoImage: ImageData | null,
  adCopy: AdCopy,
  specialRequest: string,
  aspectRatios: string[],
  imageSize: string = '1K',
  includeGooglePlay: boolean = false,
  includeAppStore: boolean = false
): Promise<PromiseSettledResult<string>[]> => {
    const adPromises: Promise<string>[] = [];

    // Create promises for every combination of Aspect Ratio and Style Variation
    // Order: For each Ratio, iterate all styles.
    for (const ratio of aspectRatios) {
        for (const variation of styleVariations) {
            adPromises.push(
                generateSingleAd(
                    productAssets,
                    lifestyleAsset,
                    styleImage,
                    logoImage,
                    adCopy,
                    specialRequest,
                    variation,
                    ratio,
                    imageSize,
                    includeGooglePlay,
                    includeAppStore
                )
            );
        }
    }

    // Return all results, successful or failed
    return await Promise.allSettled(adPromises);
};

import { useState, useCallback } from 'react';
import { generateAds, generateSingleAd, editAd, styleVariations } from '../services/geminiService';
import type { GeneratedAd, ImageData, AdCopy } from '../types';

export const useAdGenerator = () => {
  const [generatedAds, setGeneratedAds] = useState<GeneratedAd[]>([]);
  const [isGenerating, setIsGenerating] = useState(false);
  const [generalError, setGeneralError] = useState<string | null>(null);
  const [loadingMessage, setLoadingMessage] = useState<string>('');

  // Initial Generation of all variations
  const generateAllAds = useCallback(async (
    productAssets: ImageData[],
    lifestyleAsset: ImageData | null,
    styleImage: ImageData,
    logoImage: ImageData | null,
    adCopy: AdCopy,
    specialRequest: string,
    aspectRatios: string[],
    imageSize: string,
    includeGooglePlay: boolean,
    includeAppStore: boolean
  ) => {
    setIsGenerating(true);
    setGeneralError(null);
    setLoadingMessage(`Blending your ad milkshake (${imageSize})... this may take a minute.`);

    // specific ID for this batch to avoid race conditions
    const batchId = Date.now();

    // Initialize placeholders with loading state
    // We create a placeholder for every combination of (Aspect Ratio x Style Variation)
    const placeholders: GeneratedAd[] = [];
    let flatIndex = 0;

    for (const ratio of aspectRatios) {
        for (let sIdx = 0; sIdx < styleVariations.length; sIdx++) {
            placeholders.push({
                id: `${batchId}-${flatIndex}`,
                index: flatIndex,
                status: 'loading',
                imageUrl: null,
                history: [],
                aspectRatio: ratio
            });
            flatIndex++;
        }
    }

    setGeneratedAds(placeholders);

    try {
      // Use the service which now returns PromiseSettledResult[] for the flat list
      const results = await generateAds(
        productAssets,
        lifestyleAsset,
        styleImage,
        logoImage,
        adCopy,
        specialRequest,
        aspectRatios,
        imageSize,
        includeGooglePlay,
        includeAppStore
      );

      setGeneratedAds(prev => prev.map((ad, idx) => {
        const result = results[idx];
        if (result && result.status === 'fulfilled') {
          return { 
            ...ad, 
            status: 'success', 
            imageUrl: result.value, 
            history: [result.value] 
          };
        } else if (result) {
          return { 
            ...ad, 
            status: 'error', 
            error: result.reason instanceof Error ? result.reason.message : 'Generation failed' 
          };
        }
        return ad;
      }));
    } catch (e) {
      setGeneralError(e instanceof Error ? e.message : "An unexpected error occurred.");
      setGeneratedAds(prev => prev.map(ad => ({ ...ad, status: 'error', error: 'Batch failed' })));
    } finally {
      setIsGenerating(false);
      setLoadingMessage('');
    }
  }, []);

  // Regenerate a single ad slot
  const regenerateSingle = useCallback(async (
    index: number,
    productAssets: ImageData[],
    lifestyleAsset: ImageData | null,
    styleImage: ImageData,
    logoImage: ImageData | null,
    adCopy: AdCopy,
    specialRequest: string,
    // aspectRatio argument is no longer strictly needed as we get it from the ad object, 
    // but kept for API consistency if passed, or we look it up.
    passedAspectRatio: string | undefined, 
    imageSize: string,
    includeGooglePlay: boolean,
    includeAppStore: boolean
  ) => {
    // Find the ad to get its specific aspect ratio if not passed explicitly
    // (though in this design we should trust the stored state)
    let targetAd: GeneratedAd | undefined;
    setGeneratedAds(prev => {
        targetAd = prev.find(ad => ad.index === index);
        if (targetAd) {
             return prev.map(ad => ad.index === index ? { ...ad, status: 'loading', error: undefined } : ad);
        }
        return prev;
    });

    if (!targetAd) return;

    // Use the ad's stored ratio, or fallback to passed, or default.
    const effectiveAspectRatio = targetAd.aspectRatio || passedAspectRatio || '1:1';

    // Determine style variation based on modulo if we had multiple styles
    // Since we flatten (AspectRatios x Styles), the style index is (index % styleVariations.length)
    const styleIndex = index % styleVariations.length;
    const creativeDirection = styleVariations[styleIndex];

    try {
      const newImageUrl = await generateSingleAd(
        productAssets,
        lifestyleAsset,
        styleImage,
        logoImage,
        adCopy,
        specialRequest,
        creativeDirection,
        effectiveAspectRatio,
        imageSize,
        includeGooglePlay,
        includeAppStore
      );

      setGeneratedAds(prev => prev.map(ad => 
        ad.index === index ? { 
          ...ad, 
          status: 'success', 
          imageUrl: newImageUrl,
          history: [...ad.history, newImageUrl]
        } : ad
      ));

    } catch (e) {
      setGeneratedAds(prev => prev.map(ad => 
        ad.index === index ? { 
          ...ad, 
          status: 'error', 
          error: e instanceof Error ? e.message : 'Regeneration failed' 
        } : ad
      ));
    }
  }, []);

  const applyEdit = useCallback(async (index: number, prompt: string, referenceImage: ImageData | null, aspectRatio: string, imageSize: string) => {
     const currentAd = generatedAds[index];
     if (!currentAd || !currentAd.imageUrl) return;

     // Optimistic update
     setGeneratedAds(prev => prev.map(ad => 
        ad.index === index ? { ...ad, status: 'loading' } : ad
     ));

     try {
        // We use the passed aspectRatio here, but it should ideally match the ad's ratio.
        const editedUrl = await editAd(currentAd.imageUrl, prompt, referenceImage, aspectRatio, imageSize);
        setGeneratedAds(prev => prev.map(ad => 
            ad.index === index ? { 
                ...ad, 
                status: 'success', 
                imageUrl: editedUrl, 
                history: [...ad.history, editedUrl] 
            } : ad
        ));
     } catch (e) {
        setGeneratedAds(prev => prev.map(ad => 
            ad.index === index ? { ...ad, status: 'success', error: e instanceof Error ? e.message : 'Edit failed' } : ad
        ));
        setGeneralError(e instanceof Error ? e.message : "Edit failed");
     }
  }, [generatedAds]);

  const undoEdit = useCallback((index: number) => {
      setGeneratedAds(prev => prev.map(ad => {
          if (ad.index !== index || ad.history.length <= 1) return ad;
          const newHistory = ad.history.slice(0, -1);
          return {
              ...ad,
              imageUrl: newHistory[newHistory.length - 1],
              history: newHistory,
              status: 'success'
          };
      }));
  }, []);

  const revertToOriginal = useCallback((index: number) => {
    setGeneratedAds(prev => prev.map(ad => {
        if (ad.index !== index || ad.history.length <= 1) return ad;
        const original = ad.history[0];
        return {
            ...ad,
            imageUrl: original,
            history: [original],
            status: 'success'
        };
    }));
  }, []);

  return {
    generatedAds,
    isGenerating,
    loadingMessage,
    generalError,
    setGeneralError,
    generateAllAds,
    regenerateSingle,
    applyEdit,
    undoEdit,
    revertToOriginal
  };
};

import React, { useState, useCallback, useMemo } from 'react';
import type { AdCopy, ImageData } from './types';
import { generateLifestyleImage, getCopySuggestion } from './services/geminiService';
import { useAdGenerator } from './hooks/useAdGenerator';
import Header from './components/Header';
import FileInput from './components/FileInput';
import CopyInput from './components/CopyInput';
import Loader from './components/Loader';
import ErrorAlert from './components/ErrorAlert';
import ResultsDisplay from './components/ResultsDisplay';
import OutputPlaceholder from './components/OutputPlaceholder';

const App: React.FC = () => {
  // --- Assets State ---
  const [productImages, setProductImages] = useState<(ImageData | null)[]>(Array(6).fill(null));
  const [styleImage, setStyleImage] = useState<ImageData | null>(null);
  const [logoImage, setLogoImage] = useState<ImageData | null>(null);

  // --- Configuration State ---
  const [specialRequest, setSpecialRequest] = useState<string>('');
  const [selectedAspectRatios, setSelectedAspectRatios] = useState<string[]>(['1:1']);
  const [imageSize, setImageSize] = useState<string>('1K');
  const [includeGooglePlay, setIncludeGooglePlay] = useState<boolean>(false);
  const [includeAppStore, setIncludeAppStore] = useState<boolean>(false);

  // --- Selection Logic State ---
  const [lifestyleProductSelection, setLifestyleProductSelection] = useState<boolean[]>(Array(6).fill(false));
  const [adProductSelection, setAdProductSelection] = useState<boolean[]>(Array(6).fill(true));
  const [useLifestyleInAd, setUseLifestyleInAd] = useState<boolean>(true);

  // --- Lifestyle Generation State ---
  const [lifestylePrompt, setLifestylePrompt] = useState<string>('');
  const [generatedLifestyleImage, setGeneratedLifestyleImage] = useState<ImageData | null>(null);
  const [isGeneratingLifestyle, setIsGeneratingLifestyle] = useState<boolean>(false);
  const [lifestyleError, setLifestyleError] = useState<string | null>(null);

  // --- Ad Copy State ---
  const [adCopy, setAdCopy] = useState<AdCopy>({ headline: '', description: '', cta: '' });
  const [isSuggestingCopy, setIsSuggestingCopy] = useState({ headline: false, description: false, cta: false });

  // --- Ad Generation Logic (via Hook) ---
  const { 
      generatedAds, 
      isGenerating: isGeneratingAds, 
      loadingMessage, 
      generalError, 
      setGeneralError, 
      generateAllAds, 
      regenerateSingle,
      applyEdit,
      undoEdit,
      revertToOriginal
  } = useAdGenerator();

  // --- Editing State (UI only) ---
  const [editingIndex, setEditingIndex] = useState<number | null>(null);
  const [editPrompt, setEditPrompt] = useState<string>('');
  const [editReferenceImage, setEditReferenceImage] = useState<ImageData | null>(null);
  const [editRefInputKey, setEditRefInputKey] = useState<number>(0);

  const aspectRatioOptions = useMemo(() => [
    { category: 'Landscape', ratios: ['21:9', '16:9', '4:3', '3:2', '5:4'] },
    { category: 'Square', ratios: ['1:1'] },
    { category: 'Portrait', ratios: ['9:16', '3:4', '2:3', '4:5'] },
  ], []);

  // --- Handlers ---

  const handleProductImageChange = (index: number, data: ImageData | null) => {
    setProductImages(prev => {
        const newImages = [...prev];
        newImages[index] = data;
        return newImages;
    });
    // Auto-select logic
    if (data && !lifestyleProductSelection.some(Boolean)) {
        setLifestyleProductSelection(prev => { const n = [...prev]; n[index] = true; return n; });
    }
    setAdProductSelection(prev => { const n = [...prev]; n[index] = !!data; return n; });
  };

  const toggleLifestyleSelection = (index: number) => {
    if (!productImages[index]) return;
    setLifestyleProductSelection(prev => { const n = [...prev]; n[index] = !n[index]; return n; });
  };

  const toggleAdSelection = (index: number) => {
    if (!productImages[index]) return;
    setAdProductSelection(prev => { const n = [...prev]; n[index] = !n[index]; return n; });
  };

  const toggleAspectRatio = (ratio: string) => {
      setSelectedAspectRatios(prev => {
          if (prev.includes(ratio)) {
              if (prev.length === 1) return prev; // Must have at least one
              return prev.filter(r => r !== ratio);
          } else {
              if (prev.length >= 3) return prev; // Max 3
              return [...prev, ratio];
          }
      });
  };

  // Derived assets
  const selectedProductAssets = useMemo(() => {
      return productImages.filter((img, idx) => img && adProductSelection[idx]) as ImageData[];
  }, [productImages, adProductSelection]);

  const selectedLifestyleAsset = useMemo(() => {
      return (generatedLifestyleImage && useLifestyleInAd) ? generatedLifestyleImage : null;
  }, [generatedLifestyleImage, useLifestyleInAd]);

  const isFormValid = useMemo(() => {
    const hasAssets = selectedProductAssets.length > 0 || selectedLifestyleAsset !== null;
    return hasAssets && styleImage;
  }, [selectedProductAssets, selectedLifestyleAsset, styleImage]);

  const handleCopyChange = (field: keyof AdCopy, value: string) => {
    setAdCopy(prev => ({ ...prev, [field]: value }));
  };

  const handleCopySuggestion = useCallback(async (field: keyof AdCopy) => {
    if (!adCopy[field] || isSuggestingCopy[field]) return;
    setIsSuggestingCopy(prev => ({ ...prev, [field]: true }));
    try {
      const suggestion = await getCopySuggestion(field, adCopy[field]);
      setAdCopy(prev => ({ ...prev, [field]: suggestion }));
    } catch (e) {
      console.error(e); // Silent fail for copy suggestion
    } finally {
      setIsSuggestingCopy(prev => ({ ...prev, [field]: false }));
    }
  }, [adCopy, isSuggestingCopy]);

  const handleGenerateLifestyle = async () => {
    const selectedImages = productImages.filter((img, i) => img && lifestyleProductSelection[i]) as ImageData[];
    if (selectedImages.length === 0 || !lifestylePrompt.trim()) {
      setLifestyleError("Please select at least one product and provide a prompt.");
      return;
    }
    setIsGeneratingLifestyle(true);
    setLifestyleError(null);
    setGeneratedLifestyleImage(null);
    try {
        const result = await generateLifestyleImage(selectedImages, lifestylePrompt, '1:1', '1K');
        setGeneratedLifestyleImage(result);
        setUseLifestyleInAd(true); 
    } catch (e) {
        setLifestyleError((e as Error).message);
    } finally {
        setIsGeneratingLifestyle(false);
    }
  };

  const downloadImage = (imageData: ImageData, fileName: string) => {
    const link = document.createElement('a');
    link.href = `data:${imageData.mimeType};base64,${imageData.data}`;
    link.download = fileName;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  // --- Main Generation Handlers ---

  const handleSubmit = () => {
    if (!isFormValid || !styleImage) return;

    // Call Hook
    generateAllAds(
        selectedProductAssets,
        selectedLifestyleAsset,
        styleImage,
        logoImage,
        adCopy,
        specialRequest,
        selectedAspectRatios, // Pass array
        imageSize,
        includeGooglePlay,
        includeAppStore
    );
  };

  const handleRegenerateAd = (index: number) => {
    if (!styleImage) return;
    const ad = generatedAds.find(a => a.index === index);
    if (!ad) return;

    regenerateSingle(
        index,
        selectedProductAssets,
        selectedLifestyleAsset,
        styleImage,
        logoImage,
        adCopy,
        specialRequest,
        ad.aspectRatio, // Use the ad's ratio
        imageSize,
        includeGooglePlay,
        includeAppStore
    );
  };

  // --- Edit Handlers ---

  const handleSelectAdForEdit = (index: number) => {
      setEditingIndex(index);
      setEditPrompt('');
      setEditReferenceImage(null);
      setEditRefInputKey(prev => prev + 1);
  };

  const handleCancelEdit = () => {
      setEditingIndex(null);
      setEditPrompt('');
      setEditReferenceImage(null);
      setEditRefInputKey(prev => prev + 1);
  };

  const onApplyEdit = async () => {
      if (editingIndex === null || !editPrompt.trim()) return;
      const currentAd = generatedAds.find(ad => ad.index === editingIndex);
      if (!currentAd) return;

      await applyEdit(editingIndex, editPrompt, editReferenceImage, currentAd.aspectRatio, imageSize);
      setEditPrompt('');
      setEditReferenceImage(null);
      setEditRefInputKey(prev => prev + 1);
  };

  // Get currently editing ad data for preview
  const currentEditingAd = editingIndex !== null ? generatedAds.find(ad => ad.index === editingIndex) : null;
  const currentEditingImage = currentEditingAd?.imageUrl;

  return (
    <div className="bg-gray-50 min-h-screen text-slate-800 font-sans flex flex-col">
      <Header />
      <main className="container mx-auto px-4 py-8 sm:py-12 flex-grow">

        {/* Top Note */}
        <div className="mb-6 p-3 bg-yellow-50 border-l-4 border-yellow-400 text-yellow-800 text-sm rounded-r-md shadow-sm">
           <strong>Important:</strong> Please read the disclaimer at the bottom before using the tool.
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-5 gap-8 items-start">

          {/* Left Panel: Configuration */}
          <div className="lg:col-span-2">
            <div className="p-1 bg-gradient-to-br from-blue-100 via-green-100 to-yellow-100 rounded-3xl shadow-2xl">
              <div className="bg-white p-6 sm:p-8 rounded-[22px]">
                <div className="space-y-8">

                  {/* Section 1: Assets */}
