              {!isGeneratingAds && generalError && (
                  <ErrorAlert message={generalError} onClose={() => setGeneralError(null)} />
              )}

              {/* Edit Mode UI */}
              {!isGeneratingAds && currentEditingAd && currentEditingImage && (
